inlineScript.scriptBlock:
// Get the breadcrumb data (array of breadcrumb items)
var breadcrumbData = this.getData().items;
// Get configuration options
var showNumbering = this.getOption("showNumbering") !== false; // Default true
var maxItems = this.getOption("maxItems") || 0; // 0 means no limit
// Register events
this.registerEventHandlingFunction(this, "onClick",      "data");


// Get the breadcrumb container elements
var breadcrumbContainer = this.context.element.querySelector(".breadcrumb_maincontentbox");
var breadcrumbList = breadcrumbContainer.querySelector(".breadcrumb-list");



// Clear existing breadcrumb items
breadcrumbList.innerHTML = "";

// Function to create a breadcrumb item
function createBreadcrumbItem(item, index, isLast, totalItems) {
  var div = document.createElement("div");
  div.className = "breadcrumb-item";

  // Add status class if providedx
  var status = item.status;
  if (!status) {
    // Auto-determine status based on position
    if (index < totalItems - 1) {
      status = "completed";
    } else if (isLast) {
      status = "working";
    } else {
      status = "notyetstarted";
    }
  }

  // Add status class to the div for CSS styling
  div.classList.add(status);

  if (isLast) {
    div.classList.add("current");
  }

  var link = document.createElement("a");
  link.className = "breadcrumb-link";
 // link.href = item.href || "#";

  // Add status icon - directly use status value with breadcrumb_ prefix
  var iconDiv = document.createElement("div");
  iconDiv.className = "breadcrumb_" + status;
  link.appendChild(iconDiv);

  // Add text with optional numbering
  var textSpan = document.createElement("span");
  var labelText = item.label || item.text || "";
  if (showNumbering) {
    labelText = (index + 1) + ". " + labelText;
  }
  textSpan.textContent = labelText;
  link.appendChild(textSpan);

  // Add click event handler if provided
  if (item.onClick && typeof item.onClick === "function") {
    link.addEventListener("click", function(e) {
      e.preventDefault();

      item.onClick(item, index);
    });
  }

  div.appendChild(link);
  return div;
}

// Render breadcrumb items
if (breadcrumbData && Array.isArray(breadcrumbData) && breadcrumbData.length > 0) {
  var itemsToRender = breadcrumbData;

  // Apply max items limit if configured
  if (maxItems > 0 && breadcrumbData.length > maxItems) {
    // Keep first items up to maxItems
    itemsToRender = breadcrumbData.slice(0, maxItems);
  }

  // Calculate width percentage for each item
  var itemWidth = 100 / itemsToRender.length;

  // Render each breadcrumb item
  itemsToRender.forEach(function(item, index) {
    var isLast = index === itemsToRender.length - 1;
    var breadcrumbItem = createBreadcrumbItem(item, index, isLast, itemsToRender.length);
    breadcrumbItem.style.width = itemWidth + "%";
    breadcrumbList.appendChild(breadcrumbItem);
  });
} else {
  // If no data, show a default breadcrumb
  var defaultItem = createBreadcrumbItem({ label: "Home", href: "#" }, 0, true, 1);
  defaultItem.style.width = "100%";
  breadcrumbList.appendChild(defaultItem);
}

// Made with Bob

/* Breadcrumb Widget Styles - Aligned with Advance Preview */

.breadcrumb_maincontentbox {
	width: 100%;
	min-height: 35px;
	overflow: hidden;
}

.breadcrumb_maincontentbox .breadcrumb-nav{
	display: table;
	width: 100%;
}

.breadcrumb_maincontentbox .breadcrumb-nav .breadcrumb-list{
	display: flex;
	flex-direction: row;
}

.breadcrumb_maincontentbox .breadcrumb-nav .breadcrumb-list .breadcrumb-item{
	border-top: 2px solid #e0e0e0;
	width: 25%;
}

/* Status-based border colors - JavaScript adds these classes */
.breadcrumb_maincontentbox .breadcrumb-nav .breadcrumb-list .breadcrumb-item.completed{
	border-top-color: #0f62fe;
}

.breadcrumb_maincontentbox .breadcrumb-nav .breadcrumb-list .breadcrumb-item.working{
	border-top-color: #0f62fe;
}



.breadcrumb_maincontentbox .breadcrumb-nav .breadcrumb-list .breadcrumb-item .breadcrumb-link{
	background: transparent;
	display: flex;
	align-items: center;
	text-decoration: none;
	color: #0f62fe;
	outline: 2px solid transparent;
	outline-offset: -2px;
	transition: color 110ms cubic-bezier(0.2, 0, 0.38, 0.9);
}

.breadcrumb_maincontentbox .breadcrumb-nav .breadcrumb-list .breadcrumb-item .breadcrumb-link:hover {
	color: #0043ce;
	text-decoration: underline;
}

.breadcrumb_maincontentbox .breadcrumb-nav .breadcrumb-list .breadcrumb-item .breadcrumb-link:focus {
	outline: 2px solid #0f62fe;
	outline-offset: 2px;
}

.breadcrumb_maincontentbox .breadcrumb-nav .breadcrumb-list .breadcrumb-item .breadcrumb-link > span {
	padding-top: 3px;
}

.breadcrumb_maincontentbox .breadcrumb-nav .breadcrumb-list .breadcrumb-item.current .breadcrumb-link {
	color: #161616;
	cursor: default;
	pointer-events: none;
	font-weight: 600;
}

.breadcrumb_completed{
	background-image:url("data:image/svg+xml;utf8,%3Csvg%20id%3D%22icon%22%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%2232%22%20height%3D%2232%22%20viewBox%3D%220%200%2032%2032%22%3E%0A%20%20%3Cdefs%3E%0A%20%20%20%20%3Cstyle%3E%0A%20%20%20%20%20%20.cls-1%20%7B%0A%20%20%20%20%20%20%20%20fill%3A%20none%3B%0A%20%20%20%20%20%20%7D%0A%20%20%20%20%3C%2Fstyle%3E%0A%20%20%3C%2Fdefs%3E%0A%20%20%3Cpolygon%20points%3D%2214%2021.414%209%2016.413%2010.413%2015%2014%2018.586%2021.585%2011%2023%2012.415%2014%2021.414%22%20style%3D%22fill%3A%231446c6%22%2F%3E%0A%20%20%3Cpath%20d%3D%22M16%2C2A14%2C14%2C0%2C1%2C0%2C30%2C16%2C14%2C14%2C0%2C0%2C0%2C16%2C2Zm0%2C26A12%2C12%2C0%2C1%2C1%2C28%2C16%2C12%2C12%2C0%2C0%2C1%2C16%2C28Z%22%20style%3D%22fill%3A%231446c6%22%2F%3E%0A%20%20%3Crect%20id%3D%22_Transparent_Rectangle_%22%20data-name%3D%22%26lt%3BTransparent%20Rectangle%26gt%3B%22%20class%3D%22cls-1%22%20width%3D%2232%22%20height%3D%2232%22%2F%3E%0A%3C%2Fsvg%3E");
