.breadcrumb_working{
	background-image: url("data:image/svg+xml;utf8,%3Csvg%20id%3D%22icon%22%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%2232%22%20height%3D%2232%22%20viewBox%3D%220%200%2032%2032%22%3E%3Cpath%20d%3D%22M23.7642%2C6.8593l1.2851-1.5315A13.976%2C13.976%2C0%2C0%2C0%2C20.8672%2C2.887l-.6836%2C1.8776A11.9729%2C11.9729%2C0%2C0%2C1%2C23.7642%2C6.8593Z%22%20fill%3D%22%231446c6%22%2F%3E%3Cpath%20d%3D%22M27.81%2C14l1.9677-.4128A13.8888%2C13.8888%2C0%2C0%2C0%2C28.14%2C9.0457L26.4087%2C10A12.52%2C12.52%2C0%2C0%2C1%2C27.81%2C14Z%22%20fill%3D%22%231446c6%22%2F%3E%3Cpath%20d%3D%22M20.1836%2C27.2354l.6836%2C1.8776a13.976%2C13.976%2C0%2C0%2C0%2C4.1821-2.4408l-1.2851-1.5315A11.9729%2C11.9729%2C0%2C0%2C1%2C20.1836%2C27.2354Z%22%20fill%3D%22%231446c6%22%2F%3E%3Cpath%20d%3D%22M16%2C30V2a14%2C14%2C0%2C0%2C0%2C0%2C28Z%22%20fill%3D%22%231446c6%22%2F%3E%3C%2Fsvg%3E");
 	width: 24px;
	height: 24px;
	vertical-align: middle;
	background-size: 16px 16px;
	background-repeat: no-repeat;
	background-position: center;
	margin-right: 8px;
	animation: spin 1s linear infinite;
}
@keyframes spin {
	0% { transform: rotate(0deg); }
	100% { transform: rotate(360deg); }
}

